import './index.css';
import React, { useState } from 'react';
import Header from "./components/Header";
import Sidebar from './components/Sidebar';
import FormAgendamento from './components/FormAgendamento';

import FormAluno from './FormAluno';
import ListaAlunos from './ListaAlunos';
import FormPaciente from './FormPaciente';
import ListaPacientes from './ListaPacientes';
import FormDisciplina from './FormDisciplina';
import ListaDisciplinas from './ListaDisciplinas';
//import ListaAgendamentos from './bd_ListaAgendamentos';
import ListaAgendamentos from './components/ListaAgendamentos';

// ...dentro do return do componente principal:
<ListaAgendamentos />


// Função principal do App
function App() {
  const [active, setActive] = useState('dashboard');

  // Controle de atualização e edição de alunos
  const [reloadKey, setReloadKey] = useState(0);
  const [alunoEditando, setAlunoEditando] = useState(null);
  function handleNovoAluno() { setReloadKey(prevKey => prevKey + 1); }
  function handleEditar(aluno) { setAlunoEditando(aluno); }
  function handleFimEdicao() { setAlunoEditando(null); }

  // Controle de atualização e edição de pacientes
  const [reloadPacientes, setReloadPacientes] = useState(0);
  const [pacienteEditando, setPacienteEditando] = useState(null);
  function handleNovoPaciente() { setReloadPacientes(p => p + 1); }
  function handleEditarPaciente(p) { setPacienteEditando(p); }
  function handleFimEdicaoPaciente() { setPacienteEditando(null); }

  // Controle de atualização e edição de disciplinas
  const [reloadDisciplinas, setReloadDisciplinas] = useState(0);
  const [disciplinaEditando, setDisciplinaEditando] = useState(null);
  function handleNovaDisciplina() { setReloadDisciplinas(prev => prev + 1); }
  function handleEditarDisciplina(disciplina) { setDisciplinaEditando(disciplina); }
  function handleFimEdicaoDisciplina() { setDisciplinaEditando(null); }

  // Controle de atualização e edição de agendamentos
  const [reloadAgendamentos, setReloadAgendamentos] = useState(0);
  const [agendamentoEditando, setAgendamentoEditando] = useState(null);
  function handleNovoAgendamento() { setReloadAgendamentos(prev => prev + 1); }
  function handleEditarAgendamento(agendamento) { setAgendamentoEditando(agendamento); }
  function handleFimEdicaoAgendamento() { setAgendamentoEditando(null); }

  // Renderiza o conteúdo principal baseado no menu lateral selecionado
  function renderConteudo() {
    switch (active) {
      case 'dashboard':
        return (
          <div>
            <h1 className="text-3xl font-bold mb-6">Dashboard</h1>
            <p>Bem-vindo! Selecione uma opção no menu.</p>
          </div>
        );
      case 'agendar':
        return (
          <div>
            <h1 className="text-2xl font-bold mb-4">Agendar Paciente teste</h1>
            <FormAgendamento
              onNovoAgendamento={handleNovoAgendamento}
              agendamentoEditando={agendamentoEditando}
              onFimEdicao={handleFimEdicaoAgendamento}
            />
            <ListaAgendamentos
              reloadKey={reloadAgendamentos}
              onEditar={handleEditarAgendamento}
            />
          </div>
        );
      case 'disciplinas':
        return (
          <div>
            <h1 className="text-2xl font-bold mb-4">Disciplinas</h1>
            <FormDisciplina
              onNovaDisciplina={handleNovaDisciplina}
              disciplinaEditando={disciplinaEditando}
              onFimEdicao={handleFimEdicaoDisciplina}
            />
            <ListaDisciplinas
              reloadKey={reloadDisciplinas}
              onEditar={handleEditarDisciplina}
            />
          </div>
        );
      case 'pacientes':
        return (
          <div>
            <h1 className="text-2xl font-bold mb-4">Pacientes</h1>
            <FormPaciente
              onNovoPaciente={handleNovoPaciente}
              pacienteEditando={pacienteEditando}
              onFimEdicao={handleFimEdicaoPaciente}
            />
            <ListaPacientes
              reloadKey={reloadPacientes}
              onEditar={handleEditarPaciente}
            />
          </div>
        );
      case 'alunos':
        return (
          <div>
            <h1 className="text-2xl font-bold mb-4">Alunos</h1>
            <FormAluno
              onNovoAluno={handleNovoAluno}
              alunoEditando={alunoEditando}
              onFimEdicao={handleFimEdicao}
            />
            <ListaAlunos reloadKey={reloadKey} onEditar={handleEditar} />
          </div>
        );
      default:
        return <div>Selecione uma opção.</div>;
    }
  }

  // Layout principal: Header fixo, Sidebar à esquerda e conteúdo ao lado
return (
    <div className="bg-[#F6F6F8] min-h-screen">
      {/* Header fixo no topo */}
      <Header />

      {/* Flex para Sidebar + Conteúdo */}
      <div className="flex">
        {/* Sidebar (começa logo abaixo do header, por isso mt-16) */}
        <Sidebar active={active} onMenuClick={setActive} />

        {/* Conteúdo principal */}
        <main
          className="flex-1 ml-64 mt-16 p-8"
          // ml-64: igual à largura do Sidebar, mt-16: altura do Header
        >
          <div className="max-w-6xl mx-auto">{renderConteudo()}</div>
        </main>
      </div>
    </div>
  );
}

export default App;
